import Vue from 'vue'
import Vuex from 'vuex'

Vue.use(Vuex)

export default new Vuex.Store({
  state: {
    viewLoaded: false
  },
  mutations: {
    LOAD_VIEW (state, payload) {
      state.viewLoaded = payload
    }
  },
  actions: {
    loadView ({commit, state}, payload) {
      commit('LOAD_VIEW', payload)
    }
  },
  modules: {}
})
