            <h1>VIDEO</h1>
            <div class="section-content">
                <div class="content-col">
                    <span>Screen Resolution:</span>
                </div>
                <div class="content-col box">
                    <div class="content-right">
                        <select v-model="selected_resolution">
                            <option v-for="(resolution, idx) in resolutions" :key="idx" :value="resolution">{{resolution}}</option>
                        </select>
                    </div>
                </div>
            </div>
            
             <div class="section-content">
                <div class="content-col">
                    <span>Mode:</span>
                </div>
                <div class="content-col box">
                    <div class="content-right">
                        <select>
                            <option>Full Screen</option>
                            <option>Windowned</option>
                            <option>Borderless</option>
                        </select>
                    </div>
                </div>
            </div>

            <!--div class="section-content">
                <div class="content-col">
                    <span>Dynamic Resource Loading (DRL):</span>
                </div>
                <div class="content-col">
                    <div class="content-right">
                        <gz-checkbox v-model="myCheckBoxModel"/>
                    </div>
                </div>
            </div-->

        </div>
        <hr>
        
        <div class="section">
            <h1>OTHERS</h1>
            <div class="section-content">
                <div class="content-col">
                    <a class="cfgBtn" @click="OpenScreenShots">Screenshots</a>
                </div>
                <div class="content-col">
                    <a href="#" class="cfgBtn" @click="OpenLogs">Logs</a>
                </div>
                <div class="content-col">
                    <a href="#" class="cfgBtn" @click="ClearLogs">Clear Logs</a>
                </div>
            </div>
            
        </div>
        
    </div>
</template>

<script>
import gzCheckbox from './gz-checkbox.vue'

export default {
    name: 'gz-config',
    data() {
        return {
            myCheckBoxModel: true,
            resolutions: [],
            selected_resolution: null
        }
    },
    components:
    {
        gzCheckbox
    },
    async mounted()
    {
        var d3dResolutions = await this.Gunz.call('cfg.resolution');
        this.resolutions = d3dResolutions;
        /*d3dResolutions.map((val, idx) =>{
            return val
        });*/
    },
    methods: {
        async OpenScreenShots(e)
        {
            e.preventDefault();
            await this.Gunz.call('cfg.opensc');
        },
        async OpenLogs(e)
        {
            e.preventDefault();
            await this.Gunz.call('cfg.openlogs');
        },
        async ClearLogs(e)
        {
            var self = this;
            e.preventDefault();
            await this.Gunz.call('cfg.clearlogs');
            /*this.$swal({
                title: 'Wait...',
                allowEscapeKey: false,
                allowOutsideClick: false,

                didOpen: () => {
                    self.$swal.showLoading();
                    setTimeout(() => {
                        self.Gunz.call('cfg.clearlogs').then(ret => {
                            self.$swal({
                                icon: 'success',
                                title: 'Logs deleted successfully!',
                                timer: 3000,
                                showConfirmButton: false
                            });
                        });
                    }, 2000);
                }
            })*/
        }
    },
    /*watch: {
        myCheckBoxModel(val)
        {
            console.log(val);
        }
    },*/
}
</script>

