<template>

<div style="width: 100%; height: 100%">
  <div class="left">
    <div class="head-title">
      <h3>TOP 10 Players</h3>
    </div>
    <table v-if="loadedPlayers">
      <thead>
        <tr>
          <th style="width: 30px">#</th>
          <th style="width:115px">Name</th>
          <th>Level</th>
          <th>Kills</th>
          <th>Deaths</th>
        </tr>
      </thead>
      <tbody>
        <tr v-for="(item, idx) in players" :key="idx">
          <td :style="{color: RankColor(idx + 1), 'font-weight': 'bold'}">{{idx + 1}}</td>
          <td :style="{color: item.color, 'font-weight': 'bold'}">{{item.name}}</td>
          <td>{{item.level}}</td>
          <td>{{item.killCount}}</td>
          <td>{{item.deathCount}}</td>
        </tr>
      </tbody>
    </table>
  </div>

  <div class="right">
    <div class="head-title">
      <h3>TOP 10 Clans</h3>
    </div>
    <table v-if="loadedClans">
      <thead>
        <tr>
          <th style="width: 30px">#</th>
          <th style="width:115px">Name</th>
          <th>Points</th>
          <th>Wins</th>
          <th>Loses</th>
        </tr>
      </thead>
      <tbody>
        <tr v-for="(item, idx) in clans" :key="idx">
          <td :style="{color: RankColor(idx + 1), 'font-weight': 'bold'}">{{idx + 1}}</td>
          <td :style="{'font-weight': 'bold'}">{{item.name}}</td>
          <td>{{item.point}}</td>
          <td>{{item.wins}}</td>
          <td>{{item.losses}}</td>
        </tr>
      </tbody>
    </table>
  </div>
</div>

</template>

<script>
export default {
  name: 'rank',
  data () {
    return {
      loadedPlayers: false,
      players: [],
      clans: [],
      loadedClans: false,
    }
  },
  methods: {
    RankColor(idx)
    {
      var col = '#FFF';
      switch(idx)
      {
        case 1:
          col = 'lime'
        break;

        case 2:
          col = '#ff0'
        break;

        case 3:
          col = '#00ffff'
        break;
      }

      return col;
    }
  },
  async mounted()
  {
    var pRank = await this.$http.get('https://igunz.net/api/v1/characters?order_by=xp&sort_order=desc&max_records=10');
    if(pRank.status == 200)
    {
      this.players = pRank.data
      this.loadedPlayers = true;
    }

    var cRank = await this.$http.get('https://igunz.net/api/v1/clans?order_by=point&sort_order=desc&max_records=10');
    if(cRank.status == 200)
    {
      this.clans = cRank.data;
      this.loadedClans = true;
    }

    setTimeout(() => {
      this.$store.commit('LOAD_VIEW', true)
    }, 75);
  },
}
</script>

<style lang="scss">

.left
{
  position: absolute;
  width: 45%;
  height: 90%;
  top: 5%;
  left: 3%;
  background: rgba(0,0,0,.4);
  color: #efdbb7;
  padding-top: 20px;
  text-align: left;
  box-sizing: border-box;
  margin: 0 auto 40px;
  overflow-y: auto;
}

.right
{
  position: absolute;
  width: 45%;
  height: 90%;
  top: 5%;
  right: 3%;
  background: rgba(0,0,0,.4);
  color: #efdbb7;
  padding-top: 20px;
  text-align: left;
  box-sizing: border-box;
  margin: 0 auto 40px;
  overflow-y: auto;
}

.head-title
{
    margin-bottom: 10px;
    color: #fff;
    text-align: center;
}

table
{
  margin: 0;
  padding: 0;
  width: 100%;
  padding: 5px;
  border-spacing:0;
  border-collapse: collapse;
}

table thead
{
  background-color: #947a4c;
}
table th {
    padding: 5px;
    font-weight: 600;
}

table th, table td {
    margin: 0;
    position: relative;
    color: #fff;
    text-align: center;
    font-size: 16px;
}

table td {
    margin: 0;
    padding: 10px 2px;
    border: 0;
    font-size: 14px;
}

tr:nth-child(even) {
  background-color: rgba(22, 22, 22, 0.7);
}
</style>
