<template>
    <div id="app">
        <div class="topBar">
            <p class="wtitle">International GunZ Launcher</p>
            <div class="close" @click="Close()">&#xE8BB;</div>
            <div class="minimize" @click="Minimize()">&#xE921;</div>
            <!--div class="config" @click="ToggleCFG()">&#xE713;</div-->
        </div>
        <div class="sidebar">
            <div class="logo-container">
                <img src="./assets/img/final_logo-white.png" height="auto" width="75%" alt="iGunZ Logo" />
            </div>
            <div class="game-container">
                <h1 class="header">International GunZ</h1>
                <!-- Game item, more can be added -->
                <div :class="['game', activeTab == 'home' ? 'active' : '']" @click="changeTab('home')">
                    <div class="game-image">
                        <img src="./assets/img/game_news.png" height="30" width="auto" alt="International GunZ" />
                    </div>
                    <div class="game-title">
                        <p>News</p>
                    </div>
                </div>
                <div :class="['game', activeTab == 'rank' ? 'active' : '']" @click="changeTab('rank')">
                    <div class="game-image">
                        <img src="./assets/img/game_ranking.png" height="30" width="auto" alt="International GunZ" />
                    </div>
                    <div class="game-title">
                        <p>Rankings</p>
                    </div>
                </div>
                <div :class="['game', activeTab == 'rules' ? 'active' : '']" @click="changeTab('rules')">
                    <div class="game-image">
                        <img src="./assets/img/gunz-icon.png" height="30" width="auto" alt="International GunZ" />
                    </div>
                    <div class="game-title">
                        <p>Rules</p>
                    </div>
                </div>
            </div>
            <div class="button-container" @click="StartGameClicked()">
                <!--div class="button">
              <div class="text"><span>PLAY NOW</span></div>
            </div-->
                <div v-if="Update.Status == 1">
                    <div class="button">
                        <div class="down-percent"><span>{{ Update.Total }} {{ Update.TPercent }}%</span></div>
                        <div class="down-speed"><span>Downloading: {{ Update.Speed }}</span></div>
                        <!--div class="down-file"><span>File: Quest\Maps\Prison_shower_room.igz</span></div-->
                        <div class="down-file"><span>{{ Update.File }}</span></div>
                    </div>
                    <div class="download-bar">
                        <div class="progress" :style="{ width: Update.CPercent + '%' }"></div>
                    </div>
                    <div class="download-bar">
                        <div class="progress" :style="{ width: Update.TPercent + '%' }"></div>
                    </div>
                </div>
                <div class="button" v-else-if="Update.Status == 2">
                    <div class="text"><span>{{ Update.Message }}</span></div>
                </div>
                <div class="button glow" v-else-if="Update.Status == 0">
                    <div class="text"><span>PLAY NOW</span></div>
                </div>
                <div class="button" v-else>
                    <div class="text-checking">
                        <span>Checking Updates...</span>
                    </div>
                </div>
            </div>
            <div class="srv-status">
                <div class="status-left" v-if="srvStatus.length > 0">
                    <p>Status: <b :style="{ color: srvStatus == 'Online' ? 'limegreen' : 'red' }">{{ srvStatus }}</b></p>
                </div>
                <div class="status-right" v-if="plCount > -1 && srvStatus == 'Online'">
                    <p>Players: <b style="color: #ffa300">{{ plCount }}</b></p>
                </div>
            </div>
        </div>
        <div class="content">
            <transition name="fade" mode="out-in">
                <div style="width: 100%; height: 100%" v-show="routerLoaded">
                    <router-view :key="$route.fullPath" v-show="routerLoaded" />
                </div>
            </transition>
            <transition name="fade" mode="out-in">
                <div class="loading" v-show="!routerLoaded">
                    <div class="lds-facebook">
                        <div></div>
                        <div></div>
                        <div></div>
                    </div>
                </div>
            </transition>
        </div>
        <transition name="fade" mode="in-out">
            <div class="black" v-if="ShowCFG" @click="ToggleCFG()">
            </div>
        </transition>
        <transition name="zoom" mode="in-out">
            <gz-config v-if="ShowCFG" />
        </transition>
        <Keypress key-event="keyup" @success="OnEscapeKeyUP" />
    </div>
</template>
<script>
import gzConfig from './components/gz-config.vue'
export default {
    name: 'app',
    components: {
        gzConfig,
    },
    data() {
        return {
            routerLoaded: false,
            activeTab: 0,
            srvStatus: '',
            plCount: -1,
            ShowCFG: false,
            ZoomBlocked: false,
            Update: {
                CPercent: 0,
                TPercent: 0,
                Total: "?/?",
                Status: -1,
                Speed: "?? Mb/s",
                File: "??",
                Message: ""
            }
        }
    },
    methods: {
        OnEscapeKeyUP(e) {
            var key = e.event.keyCode;
            if (key == 27 && this.ShowCFG) {
                if (this.ZoomBlocked)
                    return;
                this.ShowCFG = false;
                this.ZoomBlocked = true;
                setTimeout(() => {
                    this.ZoomBlocked = false;
                }, 200);
            }
        },

        changeTab(idx) {
            var self = this;
            if (this.activeTab == idx)
                return
            this.$store.commit('LOAD_VIEW', false)
            this.activeTab = idx
            //wait show loading to work fade animation on router change
            setTimeout(() => {
                self.$router.push({ name: idx })
            }, 75);
        },

        StartGameClicked() {
            if (this.Update.Status == 0) {
                this.Update.Message = "Starting...";
                this.Update.Status = 2;
                this.Gunz.trigger('game.start');
            }
        },

        ToggleCFG() {
            if (this.ZoomBlocked)
                return;
            this.ShowCFG = !this.ShowCFG;
            this.ZoomBlocked = true;
            var self = this;
            setTimeout(() => {
                self.ZoomBlocked = false;
            }, 200);
        },

        Minimize() {
            this.Gunz.trigger('app.minimize');
        },

        Close() {
            this.Gunz.trigger('app.close');
        }
    },

    created() {
        if (this.$route.name == null)
            this.changeTab('home')
        this.activeTab = 'home'
    },

    mounted() {
        var self = this;
        //this.activeTab = this.$route.name;
        this.$store.watch(
            (state) => state.viewLoaded,
            (value) => {
                self.routerLoaded = value
            })

        this.Gunz.on('router.push', (args) => {
            if (typeof args == 'string') {
                if (this.$route.name != args)
                    this.$router.push({ path: args })
            } else if (typeof args == 'object') {
                if (args.path)
                    this.$router.push({ args })
            }
        })

        this.Gunz.on('update.percent', (arg) => {
            self.Update.Percent = arg;
        })

        this.Gunz.on('update.file', (arg) => {
            self.Update.File = arg;
            self.Update.Status = 1;
        })

        this.Gunz.on('update.speed', (arg) => {
            self.Update.Speed = arg;
        })

        this.Gunz.on('update.msg', (msg) => {
            if (self.Update.Status != 1) {
                self.Update.Status = 2;
                self.Update.Message = msg;
            }
        })

        this.Gunz.on('update.status', (arg) => {
            self.Update.File = arg['file'];
            self.Update.Speed = arg['speed'];
            self.Update.CPercent = arg['cpercent'];
            self.Update.TPercent = arg['tpercent'];
            self.Update.Total = arg['total'];

            self.Update.Status = 1;
        })

        this.Gunz.on('update.completed', () => {
            self.Update.Status = 0;
        })

        this.$http.get('https://igunz.net/api/v1/serverstatus').then(data => {
            this.srvStatus = data.data;
        })

        this.$http.get('https://igunz.net/new.igunz.net/api/v1/playercount').then(data => {
            this.plCount = data.data;
        }).catch(err => {
            console.error("Failed to fetch player count:", err);
            this.plCount = "NAN";
        });

        setTimeout(() => {
            self.Gunz.trigger('update.init');
            /*self.Update.File = 'Quest\\Maps\\Prison_shower_room.igz';
            self.Update.Status = 1;
            self.Update.CPercent = 20;
            self.Update.TPercent = 80;
            self.Update.Speed = "500 Kb/ps";*/
        }, 600);
    }
}
</script>
