<template>
    <div :id="item.id" class="accordion-item" :class="{'is-active': item.active}">
        <div class="announce-title"  @click="toggle">
            <h1>{{item.title}}</h1>
        </div>

      <transition
        name="accordion-item"
        @enter="startTransition"
        @after-enter="endTransition"
        @before-leave="startTransition"
        @after-leave="endTransition">
        <div v-if="item.active" class="announce-body" v-html="item.content">
        </div>
      </transition>
    </div>
</template>

<script>
    export default {
        name: 'gz-accordion',
        props: ['item'],
        methods: {
            toggle(event) {
                this.$parent.$children.forEach((item, index) => 
                {
                    if (item.$el.id === event.currentTarget.parentElement.id)
                    {
                        item.item.active = !item.item.active
                    }
                    else 
                        item.item.active = false
                }) 
                
            },
            startTransition(el) {
                el.style.height = el.scrollHeight + 'px'
            },
            endTransition(el) {
                el.style.height = ''
            }
        },
    }
</script>

<style lang="scss">
.accordion-item-enter-active, .accordion-item-leave-active {
  will-change: height;
  transition: height 0.2s ease;
}
.accordion-item-enter, .accordion-item-leave-to {
  height: 0 !important;
}
</style>